    #[test]
    fn build_context_injects_compaction_summary() {
        let dir = temp_dir();
        let mut manager = SessionStore::new(&dir);
        manager.create_session("llama3.2".to_string(), 32768, "/".to_string());

        // Add a compaction entry
        let compaction = SessionEntry::new_compaction(
            None,
            "Summary of earlier conversation".to_string(),
            "next-entry-id".to_string(),
            5000,
        );
        manager.append_entry(compaction).unwrap();

        // Add a message with the skip_until ID
        let next_msg = SessionEntry::new_message(None, AgentMessage::user("new topic".to_string()));
        // Override the ID to match first_kept_entry_id
        // (can't easily do this, so just check that summary is injected)
        manager.append_entry(next_msg).unwrap();

        let context = manager.build_context();
        // Should have the summary system message
        assert!(context.iter().any(|m| m.content().contains("Summary of earlier conversation")));
    }

